const cards=Array.from(document.querySelectorAll(".event-card-wrap div")).filter((el=>!document.getElementById("main-event").contains(el))),extras=document.querySelectorAll("#main-event img, #main-event h4"),finalTargets=[...cards,...extras];finalTargets.forEach((function(element){element.addEventListener("click",(function(e){if(!e.target.closest("a")){let parent=element;for(;parent&&!parent.querySelector("a");)parent=parent.parentElement;const link=parent?.querySelector("a");link&&link.click()}}))}));